1802                       E = (DFSInStack.size() - ReproducerCondStack.size());
1803              I < E; ++I) {
1804           ReproducerCondStack.emplace_back(ICmpInst::BAD_ICMP_PREDICATE,
1805                                            nullptr, nullptr);
1806         }
1807       }
1808     };
